6	// --- diff rendering (GitHub-style) ---
7	function renderDiff(text) {
8	  var lines = text.split('\n');
9	  var rows = '';
10	  var oldN = 0, newN = 0;
11	  var hasHeader = lines.some(function(l) { return l.startsWith('@@'); });
12	  var hasPlus = lines.some(function(l) { return l.startsWith('+'); });
13	  var hasMinus = lines.some(function(l) { return l.startsWith('-'); });
14	  // Plain text (Bash command, generic tool input): no diff markers — no line numbers
15	  var isPlain = !hasHeader && !hasPlus && !hasMinus;
16	  // New file: + lines but no - lines (Write of new file) — single line-number column
17	  var isNewFile = !isPlain && hasPlus && !hasMinus;
18	  var cols = isPlain ? 1 : (isNewFile ? 2 : 3);
19	  for (var i = 0; i < lines.length; i++) {
20	    var line = lines[i];
21	    var bg, sign, lOld, lNew, content;
22	    if (isPlain) {
23	      rows += '<tr><td style="padding:0 6px;font-family:monospace;font-size:11px;white-space:pre-wrap;">' + line + '</td></tr>';
24	      continue;
25	    }
26	    if (line.startsWith('@@')) {
27	      var m = line.match(/@@ -(\d+)/);
28	      if (m) { oldN = parseInt(m[1]) - 1; }
29	      m = line.match(/\+(\d+)/);
30	      if (m) { newN = parseInt(m[1]) - 1; }
31	      rows += '<tr style="background:#1e3a5f;"><td colspan="' + cols + '" style="padding:2px 8px;font-size:10px;color:#58a6ff;font-family:monospace;">' + (isNewFile ? 'new file' : line) + '</td></tr>';
32	      continue;
33	    }
34	    if (line.startsWith('-')) {
35	      oldN++;
36	      bg = 'rgba(248,81,73,0.15)';
37	      sign = '<span style="color:#da3633;user-select:none;">-</span>';
38	      lOld = oldN;
39	      lNew = '';
40	      content = line.substring(1);
41	    } else if (line.startsWith('+')) {
42	      newN++;
43	      bg = 'rgba(63,185,80,0.15)';
44	      sign = '<span style="color:#3fb950;user-select:none;">+</span>';
45	      lOld = '';
46	      lNew = newN;
47	      content = line.substring(1);
48	    } else {
49	      oldN++; newN++;
50	      bg = 'transparent';
51	      sign = ' ';
52	      lOld = oldN;
53	      lNew = newN;
54	      content = line.startsWith(' ') ? line.substring(1) : line;
55	    }
56	    if (isNewFile) {
57	      rows += '<tr style="background:' + bg + ';">' +
58	        '<td style="padding:0 6px;font-size:10px;color:var(--muted);text-align:right;user-select:none;min-width:28px;font-family:monospace;">' + lNew + '</td>' +
59	        '<td style="padding:0 4px;font-family:monospace;font-size:11px;white-space:pre-wrap;">' + content + '</td></tr>';
60	    } else {
61	      rows += '<tr style="background:' + bg + ';">' +
62	        '<td style="padding:0 6px;font-size:10px;color:var(--muted);text-align:right;user-select:none;min-width:28px;font-family:monospace;">' + lOld + '</td>' +
63	        '<td style="padding:0 6px;font-size:10px;color:var(--muted);text-align:right;user-select:none;min-width:28px;font-family:monospace;">' + lNew + '</td>' +
64	        '<td style="padding:0 4px;font-family:monospace;font-size:11px;white-space:pre-wrap;">' + sign + content + '</td></tr>';
65	    }
66	  }
67	  return '<table style="width:100%;border-collapse:collapse;border-spacing:0;">' + rows + '</table>';
68	}
